export const VALID_REQUEST_TYPES = [
  "towels",
  "toiletries",
  "pillow",
  "blanket",
  "shampoo",
  "custom",
];

export const VALID_STATUSES = ["pending", "acknowledged", "in_progress", "done"];

export interface ValidationResult {
  valid: boolean;
  errors: string[];
  data?: {
    roomId: string;
    type: string;
    customNote?: string;
  };
}

export function validateRequestBody(body: unknown): ValidationResult {
  const errors: string[] = [];

  if (!body || typeof body !== "object") {
    return {
      valid: false,
      errors: ["Request body must be a valid JSON object"],
    };
  }

  const { roomId, type, customNote } = body as Record<string, unknown>;

  // Validate roomId
  if (!roomId || typeof roomId !== "string") {
    errors.push("roomId is required and must be a string");
  } else if (!/^[a-zA-Z0-9\-]{1,20}$/.test(roomId)) {
    errors.push(
      "roomId must be alphanumeric with hyphens, max 20 characters"
    );
  }

  // Validate type
  if (!type || typeof type !== "string") {
    errors.push("type is required and must be a string");
  } else if (!VALID_REQUEST_TYPES.includes(type)) {
    errors.push(
      `type must be one of: ${VALID_REQUEST_TYPES.join(", ")}`
    );
  }

  // Validate customNote (optional)
  let sanitizedNote: string | undefined;
  if (customNote !== undefined && customNote !== null) {
    if (typeof customNote !== "string") {
      errors.push("customNote must be a string");
    } else {
      sanitizedNote = customNote.trim();
      if (sanitizedNote.length > 200) {
        errors.push("customNote must be at most 200 characters");
      }
    }
  }

  if (errors.length > 0) {
    return { valid: false, errors };
  }

  return {
    valid: true,
    errors: [],
    data: {
      roomId: (roomId as string).toUpperCase(),
      type: type as string,
      customNote: sanitizedNote || undefined,
    },
  };
}

export function validateStatusTransition(
  fromStatus: string,
  toStatus: string
): { valid: boolean; error?: string } {
  const validTransitions: Record<string, string[]> = {
    pending: ["acknowledged"],
    acknowledged: ["in_progress"],
    in_progress: ["done"],
  };

  if (fromStatus === toStatus) {
    return { valid: false, error: "Status must be different from current" };
  }

  const allowedTransitions = validTransitions[fromStatus];
  if (!allowedTransitions) {
    return {
      valid: false,
      error: `No transitions allowed from status '${fromStatus}'`,
    };
  }

  if (!allowedTransitions.includes(toStatus)) {
    return {
      valid: false,
      error: `Cannot transition from '${fromStatus}' to '${toStatus}'. Allowed: ${allowedTransitions.join(", ")}`,
    };
  }

  return { valid: true };
}

export function isValidCUID(id: string): boolean {
  // CUID format: starts with 'c' followed by 24 lowercase alphanumeric chars
  return /^c[0-9a-z]{24}$/.test(id);
}
