export type SSEEvent = "request:new" | "request:update" | "connected";

export interface SSEPayload {
  event: SSEEvent;
  data: Record<string, unknown>;
}

export class SSEBroadcaster {
  private clients: Set<ReadableStreamController<Uint8Array>> = new Set();
  private messageId: number = 0;

  subscribe(controller: ReadableStreamController<Uint8Array>) {
    this.clients.add(controller);
  }

  unsubscribe(controller: ReadableStreamController<Uint8Array>) {
    this.clients.delete(controller);
  }

  broadcast(event: SSEEvent, data: Record<string, unknown>) {
    const payload: SSEPayload = { event, data };
    const messageId = ++this.messageId;

    const message = `id: ${messageId}\nevent: ${event}\ndata: ${JSON.stringify(payload.data)}\n\n`;
    const encoded = new TextEncoder().encode(message);

    // Send to all connected clients, remove disconnected ones
    const deadClients: Set<ReadableStreamController<Uint8Array>> = new Set();

    for (const client of this.clients) {
      try {
        client.enqueue(encoded);
      } catch (error) {
        // Client disconnected, mark for removal
        deadClients.add(client);
      }
    }

    // Clean up disconnected clients
    for (const client of deadClients) {
      this.clients.delete(client);
    }
  }

  sendKeepAlive(controller: ReadableStreamController<Uint8Array>) {
    try {
      const keepAlive = new TextEncoder().encode(": keepalive\n\n");
      controller.enqueue(keepAlive);
    } catch (error) {
      this.clients.delete(controller);
    }
  }

  getClientCount(): number {
    return this.clients.size;
  }
}

// Singleton instance
export const broadcaster = new SSEBroadcaster();
